{
  "family": "agent-api",
  "taskRoleArn": "arn:aws:iam::123456789012:role/agent-api-task-role",
  "executionRoleArn": "arn:aws:iam::123456789012:role/ecs-execution-role",
  "networkMode": "awsvpc",
  "requiresCompatibilities": ["FARGATE"],
  "cpu": "512",
