      "Resource": "arn:aws:sqs:us-east-1:123456789012:agent-jobs"
    },
    {
      "Effect": "Allow",
      "Action": ["secretsmanager:GetSecretValue"],
      "Resource": "arn:aws:secretsmanager:us-east-1:123456789012:secret:agent/*"
