import time
import boto3
from botocore.exceptions import ClientError

def put_with_retry(s3_client, bucket: str, key: str, body: bytes, max_retries: int = 3) -> None:
    """Write to S3 with exponential backoff on transient errors."""
    for attempt in range(max_retries):
        try:
            s3_client.put_object(Bucket=bucket, Key=key, Body=body)
            return
        except ClientError as exc:
            code = exc.response["Error"]["Code"]
            if code in ("ServiceUnavailable", "SlowDown") and attempt < max_retries - 1:
                wait = 2 ** attempt  # 1s, 2s, 4s
                print(f"S3 transient error {code}; retrying in {wait}s")
                time.sleep(wait)
            else:
                raise
